-- ''Desbordes y tangentes'' [lagenda:42358]
INSERT INTO public.events (id, title, description, lat, lng, place_name, category, start_time, end_time, creator_id, status, external_id, photos) VALUES (
  gen_random_uuid(),
  '''Desbordes y tangentes''',
  'La exposición plantea un recorrido por distintas aproximaciones al dibujo contemporáneo, entendido ya no como una práctica limitada al papel y a lo bidimensional, sino como un lenguaje capaz de ocupar el espacio, expandirse hacia lo instalativo, lo performático o lo audiovisual, y dialogar con el cuerpo y la arquitectura.',
