-- Espectáculo de danza «Gala Stars», de International Ballet Company [tribe:elsauzal:38532]
INSERT INTO public.events (id, title, description, lat, lng, place_name, category, start_time, end_time, creator_id, status, external_id, photos) VALUES (
  gen_random_uuid(),
  'Espectáculo de danza «Gala Stars», de International Ballet Company',
  'DÍA: Jueves 4 de junio de 2026. HORA: 20.00 horas. ESPECTÁCULO: «Gala Stars». LUGAR: Teatro El Sauzal. GÉNERO: Danza clásica. COMPAÑÍA: International Ballet Company. EDAD RECOMENDADA: Sin limitaciones. DURACIÓN: 90 minutos aproximadamente. PRECIO DE ENTRADA: 38 € Tarifa Normal. 35 € Tarifa Especial (para estudiantes, menores de 25 y mayores de 65 años, y residentes en el municipio de El Sauzal). 25 € tarifa para integrantes de la Escuela de Danza, de Música y/o de Teatro. 28 € para grupos organizados (mínimo de 12 personas). SINOPSIS: Ballet Stars Gala. En esta noche mágica, se podrá disfrutar de los más impresionantes solos de algunos de los ballets más queridos de todos los tiempos. Los primeros bailarines se presentan en solitario con piezas de renombre mundial, «El Lago de los Cisnes», «Don Quijote», “Raymonda” o “El Corsario”, entre otros mostrando su talento y brindando un espectáculo inolvidable para todos los amantes de la danza. Una oportunidad única de disfrutar del ballet clásico en su máxima expresión. FICHA ARTÍSTICA/TÉCNICA: Dirección Artística: Cristina Terentiev – Alexei Terentiev. Bailarines: Cristina Terentiev, Alexandru Balan, Ilona Baitler, Sergei Zdanschi, Maria Lolenko, Alexander Litvinov, Vera Lenskaya y Peter Raikov. Iluminación: Luis Zapata. Sonido y música: Ivan Bogdan. VENTA DE ENTRADAS: Oficinas del Teatro (calle Constitución, nº 3, anexo al Ayuntamiento): martes a viernes de 08.00 a 15.00 h. (922 570 000, ext. #3004 + 607 702 749). En taquilla: 90 minutos antes de la hora de comienzo del espectáculo. Taquilla on line: Puedes comprar las entradas a través de la plataforma de venta de entradas on line , Ticketty. Clica aquí y descúbrelo. Para tarifas reducidas, se debe acreditar en taquilla. Se informa a los espectadores, que una vez comenzado el espectáculo, no se permitirá en acceso a la sala. Si deseas recibir información puntual de las actividades culturales que programamos de El Sauzal, puedes escribirnos un correo electrónico con la palabra ALTA a auditorio@elsauzal.es con tu nombre completo, teléfono y dirección de correo electrónico. Conoce toda la información de nuestro TEATRO en www.teatroelsauzal.com .',
  28.450571, -16.420905,
  'Teatro El Sauzal (Anexo al Ayuntamiento), El Sauzal',
  'culture',
  '2026-06-04 18:00:00+00',
  '2026-06-04 20:00:00+00',
  team_id, 'upcoming', 'tribe:elsauzal:38532', ARRAY['https://www.elsauzal.es/wp-content/uploads/2026/03/ballet.png']::text[]
) ON CONFLICT (external_id) DO NOTHING;
INSERT INTO public.event_tags (event_id, tag)
  SELECT id, unnest(ARRAY['culture'])
  FROM public.events WHERE external_id = 'tribe:elsauzal:38532'
ON CONFLICT DO NOTHING;

-- Acciones de puesta en valor del comercio local [tribe:elsauzal:39199]
INSERT INTO public.events (id, title, description, lat, lng, place_name, category, start_time, end_time, creator_id, status, external_id, photos) VALUES (
  gen_random_uuid(),
  'Acciones de puesta en valor del comercio local',
  'Acciones de cara rendir homenaje a esos comercios que forman parte de nuestra historia, de nuestros recuerdos y del día a día de generaciones enteras. DEL JUEVES 4 AL JUEVES 11 DE JUNIO Plaza de la avenida Inmaculada Concepción. Exposición fotográfica e informativa Gente de aquí, comercio de siempre. Vecinos y visitantes podrán disfrutar de una exposición urbana muy especial a través de diferentes tótems informativos instalados en el municipio, donde descubrirán imágenes, anécdotas e historias reales de algunos de los comercios más emblemáticos de El Sauzal. Porque detrás de cada comercio hay personas, historias y generaciones que han dado vida a nuestras calles. SÁBADO 6 DE JUNIO De 10.00 a 14.00 h. – Plaza de la avenida Inmaculada Concepción. Dinamización relacionada con el comercio local. Espacio de encuentro y memoria compartida, donde podrá acercarse, conocer más sobre el comercio local y descubrir cómo estos negocios han formado parte de la vida del Municipio a lo largo de los años. Organizan: Área de Comercio del Gobierno de Canarias y Federación de Áreas Urbanas de Canarias ( FAUCA ). Colaboran: Ayuntamiento de El Sauzal y ASEMSA.',
  28.450571, -16.420905,
  'VARIOS, El Sauzal',
  'culture',
  '2026-06-04 18:00:00+00',
  '2026-06-04 20:00:00+00',
  team_id, 'upcoming', 'tribe:elsauzal:39199', ARRAY['https://www.elsauzal.es/wp-content/uploads/2026/05/2-cartel-redes-comerciorural-sauzal.jpg']::text[]
) ON CONFLICT (external_id) DO NOTHING;
