-- VII FERIA DE SALUD. GRANADILLA DE ABONA, 2026 [tribe:granadilla-abona:44799]
INSERT INTO public.events (id, title, description, lat, lng, place_name, category, start_time, end_time, creator_id, status, external_id, photos) VALUES (
  gen_random_uuid(),
  'VII FERIA DE SALUD. GRANADILLA DE ABONA, 2026',
  'La Concejalía de Promoción de la Salud del Ilustre Ayuntamiento de Granadilla de Abona, bajo la dirección de la concejal D.ª Candelaria Chinea Niebla, organiza la VII Feria de la Salud, Granadilla de Abona 2026, con el objetivo de continuar respondiendo a la necesidad de abordar la salud desde un enfoque preventivo, promover estilos de vida saludables y acercar a la ciudadanía información relevante sobre la importancia del autocuidado. Se busca generar un espacio de participación comunitaria en el que instituciones sanitarias, organismos públicos y entidades del tercer sector trabajen de manera conjunta en beneficio de la población, fomentando la educación para la salud y la detección temprana de enfermedades. Se ha diseñado una programación de actividades dirigida a toda la ciudadanía. Contaremos con profesionales del Servicio Canario de la Salud, quienes ofrecerán talleres sobre promoción de la salud, prevención de lesiones cutáneas e higiene postural, así como talleres de Reanimación Cardiopulmonar (RCP), nutrición, actividad física y otros temas de interés sanitario ofrecido por una veintena de entidades. Nos acompañarán, entre otras, las profesionales de ATELSAM con su evento paralelo Orgullo Loco, así como el vehículo de hemodonación de parte de la Dirección General de Hemodonación y Hemoterapia. Con este motivo, se hace un llamamiento a toda la población del municipio para que done sangre. La VII Feria de la Salud. Granadilla de Abona 2026 está dirigida a toda la población en general y se celebrará el viernes, 5 de junio de 2026, en la Plaza de El Médano, en horario de 9:00 a 18:00 horas.',
  28.122031, -16.557315,
  'Granadilla de Abona, Granadilla de Abona',
  'culture',
  '2026-06-05 08:00:00+00',
  '2026-06-05 17:00:00+00',
  team_id, 'upcoming', 'tribe:granadilla-abona:44799', '{}'
) ON CONFLICT (external_id) DO NOTHING;
INSERT INTO public.event_tags (event_id, tag)
  SELECT id, unnest(ARRAY['culture'])
  FROM public.events WHERE external_id = 'tribe:granadilla-abona:44799'
ON CONFLICT DO NOTHING;

