-- “ CAMPAMENTO DE VERANO PARA PERSONAS CON DISCAPACIDAD” [tribe:granadilla-abona:44802]
INSERT INTO public.events (id, title, description, lat, lng, place_name, category, start_time, end_time, creator_id, status, external_id, photos) VALUES (
  gen_random_uuid(),
  '“ CAMPAMENTO DE VERANO PARA PERSONAS CON DISCAPACIDAD”',
  'La Concejalía de Servicios Sociales del Ilustre Ayuntamiento de Granadilla de Abona, que dirige Don Rubén García Casañas, les informa que se va poner en marcha nuevamente el Campamento de Verano para personas con discapacidad”. Dicha iniciativa contempla, como en años anteriores, un amplio número de actividades en las que destacamos, terapia con caballos, iniciación al surf, zumba, capoeira, …, además de cuentacuentos, talleres de cocina, talleres de relajación, “día sobre ruedas”, juegos de agua y piscina, playa, juegos cognitivos, etc. La realización del campamento se llevará a cabo en el CEIP Montaña Pelada (El Médano), durante los meses de julio y agosto, y se añade como mejora en este año, una ampliación del horario del campamento de verano, que pasa de las 8.00-14.00 horas a las 7.30 -14.30 horas, incorporando una hora adicional de actividades diarias, y favoreciendo con ello la conciliación familiar. El plazo de inscripción se encontrará abierto desde el día 8 de junio hasta el 19 de junio (ambos inclusive), de manera online o a través del Servicio de Atención a la Ciudadanía (SAC). Plazas limitadas.',
  28.122031, -16.557315,
  'Granadilla de Abona, Granadilla de Abona',
  'culture',
  '2026-06-08 07:00:00+00',
  '2026-06-08 22:00:00+00',
  team_id, 'upcoming', 'tribe:granadilla-abona:44802', ARRAY['https://www.granadilladeabona.org/wp-content/uploads/2026/06/Cartel-Campamento-2026-1.png']::text[]
) ON CONFLICT (external_id) DO NOTHING;
