  FROM public.events WHERE external_id = 'tribe:granadilla-abona:44802'
ON CONFLICT DO NOTHING;

-- » Taller de Ilustración: Creación de Personajes » – Concejalía de Cultura [tribe:granadilla-abona:44769]
INSERT INTO public.events (id, title, description, lat, lng, place_name, category, start_time, end_time, creator_id, status, external_id, photos) VALUES (
  gen_random_uuid(),
  '» Taller de Ilustración: Creación de Personajes » – Concejalía de Cultura',
  'El Ilustre Ayuntamiento de Granadilla de Abona, a través de la Concejalía de Cultura y Fiestas, cuyo responsable es Carlos Abismael Díaz Barreto, y el Cabildo de Tenerife invitan a la población a participar en el “ Taller de ILustración: Creación de Personajes “ , realizado por Ciara B, el jueves 11 de junio a las 18:00 horas en la Biblioteca de Granadilla de Abona. Esta actividad se encuentra dentro de la Agenda Cultural del 2º trimestre de 2026. » Taller de Ilustración: Creación de Personajes «: Este taller propone una inmersión creativa en el universo del diseño de personajes, tomando como referencia una temática seleccionada con anterioridad y por lo tanto el taller estará diseñado en base a la materia propuesta. El objetivo es fomentar la imaginación infantil mediante el desarrollo de personajes originales con elementos gráficos inspirados en estas historias. Actividad para niños/as de 6 a 12 años. Para participar en esta actividad es necesario inscribirse a través del siguiente ENLACE . Sólo es necesaria la inscripción del niño/a que vaya a participar en la actividad. El plazo de inscripción es del 1 al 9 de junio. Las plazas son limitadas. Ven y participa en nuestras actividades. ¡Te esperamos !',
  28.122572, -16.577437,
  'Biblioteca de Granadilla, Granadilla de Abona',
  'culture',
  '2026-06-11 17:00:00+00',
  '2026-06-11 19:00:00+00',
  team_id, 'upcoming', 'tribe:granadilla-abona:44769', ARRAY['https://www.granadilladeabona.org/wp-content/uploads/2026/06/CARTEL-FINAL-TALLER-DE-ILUSTRACION-11-DE-JUNIO.jpg']::text[]
) ON CONFLICT (external_id) DO NOTHING;
